// 1️⃣ Pegar o texto da IA
// =======================================

const texto = $input.first().json.text;

if (!texto) {
  throw new Error("Campo 'text' não encontrado na entrada.");
}

let parsed;

try {
  parsed = JSON.parse(texto);
} catch (error) {
  throw new Error("Erro ao fazer parse do JSON da IA.");
}

const requisitos = Object.values(parsed).map(r => ({
  descricao: r["descrição"],
  criticidade: r["criticidade"],
  esforco: r["esforço"]
}));

return [
  {
    resultado: {
      requisitos: requisitos
    }
  }
];

